import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"钢铁荷鲁斯","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/钢铁荷鲁斯.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/钢铁荷鲁斯.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/钢铁荷鲁斯.md"};function _(l,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"钢铁荷鲁斯",tabindex:"-1"},[s("钢铁荷鲁斯 "),e("a",{class:"header-anchor",href:"#钢铁荷鲁斯","aria-label":'Permalink to "钢铁荷鲁斯"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘003B")])])],-1),o('<h1 id="钢铁荷鲁斯-1" tabindex="-1">钢铁荷鲁斯 <a class="header-anchor" href="#钢铁荷鲁斯-1" aria-label="Permalink to &quot;钢铁荷鲁斯&quot;">​</a></h1><p>钢铁荷鲁斯<br> D+1000<br> 本质：科技本质<br> 这是一个单肩包形状的物体，有背带，包面上写着“IRON HORUS”，内部可以储存物品，并且有一个特制凹槽，可以装入一把截短过枪管的霰弹枪（换言之，体积不超过3）。以一个迅捷动作可以利用内置气动装置将这个单肩包展开为一面钢铁制成的长方形防暴盾牌，它的格挡防御为8点，体积4，武器伤害为3L，并可以单手持用，但只有展开时才具有武器伤害和格挡防御。当钢铁荷鲁斯展开时，持有者可以以一个自由动作取出凹槽中装入的霰弹枪，若未使用迅捷动作在战斗场景中展开这面盾牌，则仍需以正常动作取出这把霰弹枪。<br> 当持有这面盾牌且使用霰弹枪进行攻击时，获得抵近射击的射击技巧，可以将射击结合在移动之中，但移动速度降低至原来的一半，若如此做，则本轮内获得钢铁荷鲁斯所提供的格挡防御，但并不视为进行了一次格挡。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
